DECLARE
V_COUNT INTEGER;
BEGIN
SELECT COUNT(TABLE_NAME) INTO V_COUNT from USER_TABLES where TABLE_NAME = '__EFMigrationsHistory';
IF V_COUNT = 0 THEN
Begin
BEGIN 
EXECUTE IMMEDIATE 'CREATE TABLE 
"__EFMigrationsHistory" (
    "MigrationId" NVARCHAR2(150) NOT NULL,
    "ProductVersion" NVARCHAR2(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
)';
END;

End;

END IF;
EXCEPTION
WHEN OTHERS THEN
    IF(SQLCODE != -942)THEN
        RAISE;
    END IF;
END;
/

BEGIN 
EXECUTE IMMEDIATE 'CREATE TABLE 
"DISPOSITIVO" (
    "ID" NUMBER(19) GENERATED BY DEFAULT ON NULL AS IDENTITY NOT NULL,
    "IDENTIFICADOR_PUBLICO" VARCHAR2(64) NOT NULL,
    "NOME" VARCHAR2(120) NOT NULL,
    "COMERCIANTE_ID" VARCHAR2(64) NOT NULL,
    "CHAVE_PUBLICA_PEM" CLOB NOT NULL,
    "STATUS" VARCHAR2(20) NOT NULL,
    "DATA_REGISTRO" TIMESTAMP NOT NULL,
    "DATA_BLOQUEIO" TIMESTAMP,
    "MOTIVO_BLOQUEIO" VARCHAR2(500),
    CONSTRAINT "PK_DISPOSITIVO" PRIMARY KEY ("ID")
)';
END;
/

BEGIN 
EXECUTE IMMEDIATE 'CREATE TABLE 
"LOG_AUDITORIA" (
    "ID" NUMBER(19) GENERATED BY DEFAULT ON NULL AS IDENTITY NOT NULL,
    "DISPOSITIVO_ID" NUMBER(19) NOT NULL,
    "LOTE_ID" VARCHAR2(64) NOT NULL,
    "TRANSACAO_ID" VARCHAR2(64) NOT NULL,
    "TIMESTAMP_TRANSACAO" TIMESTAMP NOT NULL,
    "TIMESTAMP_RECEBIMENTO" TIMESTAMP NOT NULL,
    "STATUS_VALIDACAO" VARCHAR2(30) NOT NULL,
    "HASH_TRANSACAO" VARCHAR2(64) NOT NULL,
    "HASH_ANTERIOR" VARCHAR2(64) NOT NULL,
    "OBSERVACAO" VARCHAR2(500),
    CONSTRAINT "PK_LOG_AUDITORIA" PRIMARY KEY ("ID"),
    CONSTRAINT "FK_LOG_AUDITORIA_DISPOSITIVO_DISPOSITIVO_ID" FOREIGN KEY ("DISPOSITIVO_ID") REFERENCES "DISPOSITIVO" ("ID") ON DELETE CASCADE
)';
END;
/

CREATE INDEX "IX_DISP_COMERCIANTE_STATUS" ON "DISPOSITIVO" ("COMERCIANTE_ID", "STATUS")
/

CREATE UNIQUE INDEX "IX_DISP_IDENT_PUBLICO" ON "DISPOSITIVO" ("IDENTIFICADOR_PUBLICO")
/

CREATE INDEX "IX_LOG_DISP_TIMESTAMP" ON "LOG_AUDITORIA" ("DISPOSITIVO_ID", "TIMESTAMP_TRANSACAO")
/

CREATE INDEX "IX_LOG_LOTE_ID" ON "LOG_AUDITORIA" ("LOTE_ID")
/

